using System; using System.Linq; using System.Data.Entity; using System.Windows; using System.Windows.Controls; using WarehouseManagement.ApplicationData;
namespace WarehouseManagement.Pages { public partial class LoginPage:Page { public LoginPage(){InitializeComponent();} private void btnLogin_Click(object s,RoutedEventArgs e){var login=txtLogin.Text.Trim(); var pass=txtPassword.Password; var u=AppConnect.model01.Users.Include("UserRoles").FirstOrDefault(x=>x.Login==login&&x.Password==pass); if(u==null||u.IsBlocked){MessageBox.Show("Неверный логин, пароль или пользователь заблокирован"); return;} AppConnect.CurrentUser=u; WarehouseService.Log("Вход","Users",u.UserID,"Авторизация в системе"); AppFrame.frmMain.Navigate(new InventoryOverviewPage());} private void btnReg_Click(object s,RoutedEventArgs e){AppFrame.frmMain.Navigate(new UserRegistrationPage());}}}
